import os
import anthropic

API_KEY = os.getenv('DATABASE_API_KEY')

class AuthMiddleware:
    def __init__(self):
        self.api_key = API_KEY

    def inject_auth(self, tool_call):
        if tool_call['name'] in ['query_db', 'user_profile']:
            tool_call['headers'] = tool_call.get('headers', {})
            tool_call['headers']['Authorization'] = f'Bearer {self.api_key}'
        return tool_call

