def execute_with_auth_retry(client, tool_call, max_retries=3):
    for attempt in range(max_retries):
        try:
            if attempt == 0:
                # Try without auth
                pass
            elif attempt == 1:
                tool_call['headers']['X-API-Key'] = os.getenv('API_KEY')
            else:
                tool_call['headers']['Authorization'] = f'Bearer {os.getenv("BEARER_TOKEN")}'

            result = client.tools.call(tool_call)
            if result.get('status_code') in [401, 403]:
                raise Exception('Auth failed')
            return result
        except Exception:
            if attempt == max_retries - 1:
                raise
    return None

# Use with Claude agent loop

AGENT_ROLES = {
    'readonly': ['get_user_info'],
    'admin': ['query_db', 'update_user']
}

def authorize_tool_call(agent_role, tool_name):
    return tool_name in AGENT_ROLES.get(agent_role, [])

def filter_claude_tools(message, agent_role):
    filtered_content = []
    for block in message.content:
        if block.type == 'tool_use':
            if authorize_tool_call(agent_role, block.name):
                filtered_content.append(block)
            else:
                filtered_content.append({
                    'type': 'text',
                    'text': f'Access denied to {block.name}'
                })
        else:
            filtered_content.append(block)
    return filtered_content

